INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1567, 142736, 6, 248, 'cry~~', '独自一个人走在热闹的中山路，身旁是来来往往的人群，却没有一个我认识的人，有点凄凉！突然开始想他，疯狂地想他，想他的脸庞，想他的语言，想他的一切一切，好像还很熟悉，但是他却不在身边了。身后的音像店偏偏很不解风情地传来江美琪的声音“亲爱的你怎么不在我身边......”，一时间，压抑了很久的眼泪再也忍不住了，潸然泪下。路人们惊异的眼神，我也管不了那么多了，那一刻，我只想痛痛快快地哭一场。', '独自一个人走在热闹的中山路，身旁是来来往往的人群，却没有一个我认识的人，有点凄凉！突然开始想他，疯狂地想他，想他的脸庞，想他的语言，想他的一切一切，好像还很熟悉，但是他却不在身边了。身后的音像店偏偏很不解风情地传来江美琪的声音“亲爱的你怎么不在我身边......”，一时间，压抑了很久的眼泪再也忍不住了，潸然泪下。路人们惊异的眼神，我也管不了那么多了，那一刻，我只想痛痛快快地哭一场。', '我像是咖啡豆，随时都有粉身的准备，亲爱的你，请将我磨碎 。我满溢的泪，会蒸馏出滚烫的水，再将我的思念溶解，化为少许糖味，盛装一杯咖啡，陪你度过，每个不眠的夜！', '2002-01-22 15:16:00', 8, '20030317224629_bbsid_142736_board_6_b376f59305.html', '20030317224629');
